  ('locality-6f0ba476-moex-00530', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '人頭稅式的定額稅，違反下列那一項租稅課徵的原則？', '["效率性原則", "垂直公平原則", "中立性原則", "確實原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00531', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '關於租稅歸宿之敘述，下列何者錯誤？', '["其他條件不變下，在完全競爭市場中，需求愈有彈性，生產者租稅負擔愈大", "其他條件不變下，在完全競爭市場中，供給愈有彈性，消費者租稅負擔愈大", "對追求利潤極大的獨占廠商課徵利潤稅，不會影響其商品的價格", "獨占廠商必可將租稅完全轉嫁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
